"""Hand-crafted Japanese translations for Distinction II words 201-400."""

PART2 = {
201: {"nativeDefinition": "To have a particular fondness or weakness for something.", "japaneseMeaning": "（何かに）弱い、特別な好みがある", "etymology": "soft spot（柔らかい場所）が比喩的に、心の弱い部分・好きな対象を表す。", "examples": {"B": "限定版のお菓子には弱い。", "C": "初恋の彼女への気持ちがまだ残っている。どうすればいいんだろう。", "D": "何かに弱い"}},
202: {"nativeDefinition": "For the period ahead that can reasonably be predicted.", "japaneseMeaning": "当面の間、近い将来にわたって", "etymology": "foreseeable（予見可能な）＋ future（未来）で、見通せる範囲の将来を指す。", "examples": {"B": "世界でもっとチャンスを掴むために、当面の間日本を離れることにした。", "C": "カーリーは当面の間、もう子どもは作らないと言っていた。他のことに集中したいらしい。", "D": "この時点で見通せる近い将来"}},
203: {"nativeDefinition": "A person who gives unwanted advice or criticism about how something should be done.", "japaneseMeaning": "口出しばかりする人、おせっかいな指導者", "etymology": "運転席の後ろ（back seat）から運転に口出しする人という比喩から。", "examples": {"B": "マネージャーはいつも人に指示ばかり出すけど、自分で実際に仕事しているところを見たことがない。まさに口出しばかりの人だ。", "C": "口出しするなよ。自分で何をしているかわかってる。", "D": "細かく管理しすぎる人"}},
204: {"nativeDefinition": "To be strict, critical, or demanding toward someone.", "japaneseMeaning": "（人に）厳しい、容赦ない", "etymology": "hard（厳しい）＋ on（〜に対して）で、人に厳しく当たることを表す。", "examples": {"B": "プロジェクトの締め切りがかなり無理なので、ブライアンは最近チームにかなり厳しくなっている。", "C": "ビルは入院を退院したばかりだからあまり厳しく言いたくないけど、ここ数日はちょっと動きが遅い。", "D": "人に厳しい"}},
205: {"nativeDefinition": "To evoke strong emotions, especially sadness or sympathy.", "japaneseMeaning": "心を揺さぶる、感情を動かす", "etymology": "heartstrings（心の弦）を引く（pull）という比喩で、深い感情を呼び起こすことを表す。", "examples": {"B": "韓国ドラマは人の心を揺さぶるのがうまい。見るたびに涙が止まらない。", "C": "このシーンは見るたびに泣いてしまう。本当に心を揺さぶられる。", "D": "人を感情的にさせる"}},
206: {"nativeDefinition": "To pay the bill or cover the cost of something.", "japaneseMeaning": "（代金を）払う、費用を負担する", "etymology": "foot（歩く）the bill（請求書）で、請求書の分を歩いて運ぶ＝支払うという意味から。", "examples": {"B": "みんな10ドルずつ出してくれれば、残りは僕が払うよ。", "C": "僕の意見では、女性が男性に代金を払うことを期待すべきではない。ただ、男性からデートに誘われたなら払うべきだと思う。", "D": "残りを払う。全部払う。"}},
207: {"nativeDefinition": "Extremely happy and elated.", "japaneseMeaning": "有頂天だ、絶好調で幸せだ", "etymology": "世界の頂上（top of the world）にいるという比喩で、最高の気分を表す。", "examples": {"B": "彼氏が理由もなく花束をくれたから、彼女は今有頂天だ。", "C": "長いプロジェクトを終えた後、有頂天だった。", "D": "とても幸せ"}},
208: {"nativeDefinition": "To return to fundamental principles before adding complexity.", "japaneseMeaning": "基本に立ち返る", "etymology": "basics（基本）に戻る（get back）ことで、本質からやり直すことを表す。", "examples": {"B": "ITチームは派手な機能を足す前に、まずソフトが起動するかどうかを確認するなど、基本に立ち返る必要がある。", "C": "基本に立ち返って、教育と教室を本当に根本的なレベルから改善していこう。", "D": "基本に戻る"}},
209: {"nativeDefinition": "To delay dealing with something instead of acting on it promptly.", "japaneseMeaning": "（仕事などを）先延ばしにする、放置する", "etymology": "sit on（上に座る）が比喩的に、物事を処理せずに押さえておくことを表す。", "examples": {"B": "その仕事を放置するのはやめて、もう送ってくれ。明日レビューしないと。", "C": "ジョージがこの課題の部分を放置している理由、わかる？", "D": "何かを先延ばしにする"}},
210: {"nativeDefinition": "To insist on a decision or resolution when someone is avoiding it.", "japaneseMeaning": "（決着を）迫る、はっきりさせる", "etymology": "force（強いる）the issue（問題）で、曖昧にせず決着を迫ることを表す。", "examples": {"B": "給料の支払いを先延ばしにされているから、そろそろはっきりさせないと。", "C": "この子が僕のことを好きかどうかわからない。はっきりした返事をくれないんだ。そろそろはっきりさせる時期だと思う。", "D": "決断を迫る"}},
211: {"nativeDefinition": "To consider or interpret something from a particular perspective.", "japaneseMeaning": "ある見方で〜と捉える", "etymology": "certain light（ある光）で見るという比喩で、特定の視点から物事を解釈することを表す。", "examples": {"B": "ある見方では、さっき食べた特別メニューはチーズを足したサラダの丼だった。別にすごいものじゃなかった。", "C": "ある見方で捉えれば、日本語は英語より優れた言語になりうる。", "D": "特定の視点から何かを考える"}},
212: {"nativeDefinition": "Generally; considering everything overall.", "japaneseMeaning": "概して、全体的に見れば", "etymology": "航海用語に由来し、風向きを大まかに見て帆を調整することから、おおまかにという意味になった。", "examples": {"B": "上司がちょっと頑固なところはあるけど、概して職場には満足している。", "C": "概して、人は寝るのが好きだ。", "D": "すべてを考慮すると、一般的に"}},
213: {"nativeDefinition": "To annoy or frustrate someone intensely (often used hyperbolically).", "japaneseMeaning": "（人を）苛立たせる、耐えられない", "etymology": "killing（殺す）が比喩的に、非常に苛立たせることを表す口語表現。", "examples": {"B": "日本語の文書を英語に翻訳するのは彼をイライラさせているようだ。母語が日本語でも英語でもないから。", "C": "口を開けたまま噛むのやめてくれない？耐えられない。", "D": "人を苛立たせる"}},
214: {"nativeDefinition": "To accept and tolerate something unpleasant.", "japaneseMeaning": "（嫌なことを）受け入れる、我慢する", "etymology": "live with（〜と生きる）で、避けられない状況と共存することを表す。", "examples": {"B": "失敗は受け入れられる。でも挑戦しないことは受け入れられない。", "C": "医者は1日1杯のアルコールまでと言った。それは我慢できないと思う。", "D": "何かを我慢する"}},
215: {"nativeDefinition": "To deviate from the intended course or topic.", "japaneseMeaning": "（話題・計画が）脱線する、本筋から外れる", "etymology": "track（線路）から外れる（off）という比喩で、本来の方向から逸れることを表す。", "examples": {"B": "会話が思ったより長引いた。終わりの方でマイケルが話を脱線させてしまった。", "C": "プロジェクトは先週ちょっと脱線したから、今週はもう少し頑張って立て直さないと。", "D": "本筋から外れる"}},
216: {"nativeDefinition": "To recover quickly and successfully from a setback.", "japaneseMeaning": "（困難から）立ち直る、うまく乗り切る", "etymology": "猫が高所から落ちても足で着地するという俗信から、困難後にうまく立ち直ることを表す。", "examples": {"B": "彼を解雇しなければならなかったのは残念だけど、どこかでうまく立ち直って成功するだろう。", "C": "家が焼けた後、彼がどうやって立ち直ったかには感心した。", "D": "すぐに立ち直る"}},
217: {"nativeDefinition": "Hopefully; wishing for good luck.", "japaneseMeaning": "うまくいきますように、願いを込めて", "etymology": "十字の指を交差させて幸運を祈る西洋のジェスチャーに由来する。", "examples": {"B": "雨が降る前に家に着けますように。難しいかもしれないけど。", "C": "2ヶ月間勉強したから、いい点が取れますように。", "D": "うまくいくといいな"}},
218: {"nativeDefinition": "Something that is already decided and certain to happen.", "japaneseMeaning": "決定事項、もう決まっていること", "etymology": "done（完了した）deal（取引）で、すでに成立した取引＝確定事項を表す。", "examples": {"B": "ロンドン支店への異動はもう決まっている。来週引っ越すことになった。", "C": "彼との関係はもう終わりだ。たとえ戻っても以前とは同じにはならない。前に進んだ方がいい。", "D": "確定したこと"}},
219: {"nativeDefinition": "An opportunity has passed and can no longer be taken.", "japaneseMeaning": "もう手遅れだ、機会は過ぎた", "etymology": "出航した船（ship）はもう追えないという比喩で、逃した機会を表す。", "examples": {"B": "今からチケットは買えない。もう手遅れだ。昨日売り切れた。", "C": "最近の子どもたちは数年後にユーチューバーになりたいと言うけど、その頃にはもう手遅れだろう。", "D": "その機会は逃した"}},
220: {"nativeDefinition": "Systems that limit power and prevent abuse of authority.", "japaneseMeaning": "抑制と均衡、権力の牽制", "etymology": "checks（抑制）とbalances（均衡）で、権力の暴走を防ぐ仕組みを表す。", "examples": {"B": "連邦政府には大統領が好き勝手できないよう、抑制と均衡の仕組みがある。", "C": "組織内には、人が勝手に自分宛てに送金できないよう、牽制の仕組みがある。", "D": "問題を防いだり発見したりする仕組み"}},
221: {"nativeDefinition": "To make a tense or sad atmosphere more relaxed and cheerful.", "japaneseMeaning": "雰囲気を和らげる", "etymology": "mood（雰囲気）を軽くする（lighten）という直訳的な表現。", "examples": {"B": "人が泣いているとき、いつも冗談を言って雰囲気を和らげようとするんだけど、みんな黙れって言われる。", "C": "誰かが怪我をしたときに雰囲気を和らげるのは難しい。", "D": "雰囲気を良くする"}},
222: {"nativeDefinition": "Something similar to what was just mentioned.", "japaneseMeaning": "そんな感じのもの、それに近いもの", "etymology": "those lines（その線・方向）に沿った（along）何かという意味。", "examples": {"B": "ファンタか、そんな感じの缶飲料を買ってきてくれる？", "C": "時間とお金に余裕があったら何の趣味を始める？僕なら世界旅行、そんな感じかな。", "D": "似たようなもの"}},
223: {"nativeDefinition": "To do something purely for the sake of doing it, without clear purpose.", "japaneseMeaning": "なんとなくやる、目的なく続ける", "etymology": "sake（ため）で行う（do）ことから、明確な目的なく行動することを表す。", "examples": {"B": "最近仕事の生産性が落ちている理由の一つは、なんとなく仕事をしている感じがしてきたからだと思う。", "C": "明確な目標なく、なんとなく勉強する学生が多い。それが最大の問題だ。", "D": "明確な目的なく何かをする"}},
224: {"nativeDefinition": "Excellent, stylish, or perfectly appropriate.", "japaneseMeaning": "完璧な、洗練されている", "etymology": "on point（要点に合っている）がスラング的に「完璧」「おしゃれ」を表すようになった。", "examples": {"B": "その髪型、すごく完璧だね。", "C": "そのスーツどこで買ったの？本当に洗練されてる。", "D": "おしゃれな"}},
225: {"nativeDefinition": "To speak briefly and privately with someone.", "japaneseMeaning": "（人と）ちょっと話をする", "etymology": "have a word（一言）で、短く話をすることを表す。", "examples": {"B": "上司の行動が非常に不適切なので、人事担当者とちょっと話をするつもりだ。", "C": "ねえ、ちょっと二人で話せる？伝えたいことがあるんだ。", "D": "人と短く話す"}},
226: {"nativeDefinition": "A precaution or backup plan to protect against risk.", "japaneseMeaning": "保険、万が一の備え", "etymology": "insurance policy（保険契約）が比喩的に、リスクに備える手段を表す。", "examples": {"B": "スピーチの一部を忘れたときのために、メモを持ってきた。保険みたいなものだ。", "C": "彼女がいるのに独身のふりをする女の子がまだいるのは不思議だ。うまくいかなかったときの保険なのかな。", "D": "リスク軽減策"}},
227: {"nativeDefinition": "Easily angered; quick-tempered.", "japaneseMeaning": "短気な、すぐ怒る", "etymology": "hot-headed（熱い頭）で、感情がすぐ沸騰する人を表す。", "examples": {"B": "このブログ記事によると、短気な人は強い個性を持ちがちだと書いてある。なんとなく本当だと思う。", "C": "彼はかなり短気だから、挑発しないようにして。", "D": "すぐ怒る"}},
228: {"nativeDefinition": "It is wiser to be cautious than to risk regret.", "japaneseMeaning": "用心するに越したことはない", "etymology": "安全（safe）な方が後悔（sorry）よりましという教訓的な表現。", "examples": {"B": "ラテがいいのかカプチーノがいいのか覚えていなかったから、両方注文した。用心するに越したことはない。", "C": "パーティー用の飲み物を多めに注文しちゃったけど、用心するに越したことはないよね？", "D": "不注意より用心する方が賢明だ"}},
229: {"nativeDefinition": "To risk everything on a single option or strategy.", "japaneseMeaning": "一つのことに全てを賭ける", "etymology": "一つの籠（basket）に全ての卵（eggs）を入れるという比喩から。", "examples": {"B": "最初のツアーに全財産を賭けたいけど、一つのことに全てを賭けるべきじゃないのはわかっている。", "C": "投資の際は一つのことに全てを賭けないよう注意するよう、ファイナンシャルアドバイザーに言われた。", "D": "成功のために一つの手段だけに頼る"}},
230: {"nativeDefinition": "To group items or tasks together for efficiency.", "japaneseMeaning": "（作業などを）まとめる、一括する", "etymology": "batch（一括）で、個別ではなくまとめて処理することを表す。", "examples": {"B": "みんなが別々に注文するより、まとめてトムに任せよう。", "C": "家事は毎日ではなく、洗濯は決まった曜日にするなど、まとめてやるのが好きだ。", "D": "何かをグループ化する"}},
231: {"nativeDefinition": "To maintain progress and momentum.", "japaneseMeaning": "（物事を）前に進め続ける", "etymology": "things（物事）を動かし続ける（keep moving）という意味。", "examples": {"B": "今日はみんな体調が悪いのはわかるけど、彼がいなくても物事を前に進め続けないと。", "C": "胃と腸は考える器官だ。不安は消化管の筋肉に影響し、物質が通過し続けるのを保つ。", "D": "進捗を維持する"}},
232: {"nativeDefinition": "To encounter a significant obstacle or difficulty.", "japaneseMeaning": "（大きな）障害にぶつかる", "etymology": "roadblock（道路封鎖）にぶつかる（hit）という比喩的な表現。", "examples": {"B": "要するに、障害にぶつかったときにどう対処するかを事前に計画することが、キャリア成功の鍵だ。", "C": "障害にぶつかったと思ったら、一歩下がって根本原因を考えてみよう。", "D": "困難に遭遇する"}},
233: {"nativeDefinition": "Used when something happens for the first time, often surprisingly.", "japaneseMeaning": "それは初めてだね、珍しいことだ", "etymology": "that's a first（それは初めてだ）で、今までにない出来事への驚きを表す。", "examples": {"B": "エブリンが時間通りに来た。それは初めてだね。", "C": "それは初めてだ。母が満点じゃなかったことを責めなかった。", "D": "それは新しいことだ"}},
234: {"nativeDefinition": "Annoyed or bored to the point of frustration.", "japaneseMeaning": "うんざりしている、もう嫌だ", "etymology": "feed up（満腹にする）の受動態で、我慢の限界に達した状態を表す。", "examples": {"B": "彼女はデートで遅刻する僕にうんざりしている。仲直りしないと。", "C": "上司は締め切りを守れない僕にうんざりしているみたいだ。", "D": "うんざりした"}},
235: {"nativeDefinition": "To agree with each other; to share the same opinion.", "japaneseMeaning": "意見が一致する、同じ考えを持つ", "etymology": "目と目が合う（see eye to eye）という比喩で、意見が一致することを表す。", "examples": {"B": "彼女とはよく喧嘩する。多くのことで意見が一致しない。", "C": "いつも意見が一致するとは限らないけど、両親のことはいつも愛している。", "D": "お互いに同意する"}},
236: {"nativeDefinition": "To persist and endure through a difficult situation.", "japaneseMeaning": "（困難を）耐え抜く、最後まで頑張る", "etymology": "stick it out（それを突き通す）で、困難な状況をやり抜くことを表す。", "examples": {"B": "頼んだことは本当に難しいのはわかっている。でも耐え抜けば、最後に大きな報酬があるかもしれない。", "C": "仕事を辞めたいけど、耐え抜くべきかとも思う。板挟みだ。", "D": "最後まで粘り強く続ける"}},
237: {"nativeDefinition": "When considering the overall or long-term perspective.", "japaneseMeaning": "大局的に見れば、長い目で見れば", "etymology": "grand scheme（大きな計画・全体像）の中で（in）という意味。", "examples": {"B": "前向きにいこう。大局的に見れば、困難はキャリアにとって良いことだ。", "C": "そんなに落ち込まないで。大局的に見れば、君のミスはそれほど大したことじゃない。", "D": "全体の観点から"}},
238: {"nativeDefinition": "By itself; considered alone without other factors.", "japaneseMeaning": "それ自体として、単体で見れば", "etymology": "in and of itself で、他の要素を除いてそれだけでという意味。", "examples": {"B": "この刺身はそれ自体で本当においしい。醤油も要らない、何も足す必要はない。", "C": "残業を増やすだけではこの問題は解決しない。どこでコストを削れるかも見る必要がある。", "D": "それ自体で"}},
239: {"nativeDefinition": "To complete and deliver something, especially work.", "japaneseMeaning": "（仕事などを）仕上げて出す、完了させる", "etymology": "out the door（外に出す）で、完成品を外に出す＝納品・完了することを表す。", "examples": {"B": "このレポートを整えて出して、みんな帰ろう。", "C": "出す前にこの記事を校正しないと。明日早朝にやるつもりだ。", "D": "何かを完了させる"}},
240: {"nativeDefinition": "To rely on or count on something happening.", "japaneseMeaning": "（何かを）当てにする、確信する", "etymology": "bank（銀行）on（〜に）で、お金を預けるように信頼することを表す。", "examples": {"B": "今年のボーナスは当てにしない方がいい。", "C": "錦織が次の試合に勝つのは当てになるよ。今すごく好調なテニスをしている。", "D": "何かを当てにする"}},
241: {"nativeDefinition": "A general term that covers many different specific things.", "japaneseMeaning": "総称、包括的な呼び方", "etymology": "blanket（毛布）term（用語）で、広く覆う一般的な呼び名を表す。", "examples": {"B": "ラーメンを麺類スープの総称として使うのはやめてほしい。うどんもそばもラーメンじゃない。", "C": "アジア系アメリカ人は、今アメリカに住む様々なアジア系の人々を指す総称だ。", "D": "一般的な呼び方"}},
242: {"nativeDefinition": "To speak bluntly without considering how words affect others.", "japaneseMeaning": "遠慮なく話す、口に出す前に考えない", "etymology": "filter（フィルター）がない（no）で、言葉を選ばずに話すことを表す。", "examples": {"B": "子どもは遠慮がない。4歳の娘に犬が飼えない理由を言ったら、おじいちゃんが引っ越せばいいって言った。", "C": "トレーシーを顧客対応の役割に就かせるべきじゃない。遠慮がないから。", "D": "とても率直に話す"}},
243: {"nativeDefinition": "To establish a high standard or expectation.", "japaneseMeaning": "基準を上げる、高い水準を示す", "etymology": "bar（ハードル）を高く（high）設定する（set）という比喩。", "examples": {"B": "マイケルは素晴らしいパフォーマンスで、他の競技者に高いハードルを示した。", "C": "ハードルを上げすぎたくはないけど、少なくとも売上5%成長を目指すべきだと思う。", "D": "目標を引き上げる"}},
244: {"nativeDefinition": "To investigate thoroughly to find the true cause of something.", "japaneseMeaning": "（原因を）徹底的に究明する", "etymology": "bottom（底）まで到達する（get to）という比喩で、根本まで調べることを表す。", "examples": {"B": "ノートパソコンが起動しない原因を究明しようとしている。", "C": "先進国なのに日本のジェンダー平等がひどい理由を究明する価値はあると思う。", "D": "何かの根本原因を見つける"}},
245: {"nativeDefinition": "There is nothing that can be done about it.", "japaneseMeaning": "仕方がない、どうしようもない", "etymology": "can't be helped で、変えられない状況を受け入れる日本語の「仕方がない」に相当する表現。", "examples": {"B": "レストランは満席だったから、別の店を選んだ。仕方ない。", "C": "誰にでも少しは自己中心的なところがある。人間の本性で、仕方ない。", "D": "変えられない"}},
246: {"nativeDefinition": "In the past; during an earlier time.", "japaneseMeaning": "昔は、当時は", "etymology": "back in the day で、過去のある時期を懐かしむように指す表現。", "examples": {"B": "昔は服にお金をたくさん使っていた。", "C": "祖母はいつも昔は人々が親切だったと言い続ける。うんざりする。", "D": "過去に"}},
247: {"nativeDefinition": "Making no progress; stuck without advancement.", "japaneseMeaning": "（話・仕事が）進展しない、行き詰まっている", "etymology": "going nowhere（どこにも行かない）で、前に進まない状態を表す。", "examples": {"B": "この会話は進展しないから、もう少し問題について考える時間を取って、明日また続けよう。", "C": "キャリアが行き詰まっていたから転職することにした。新しい環境で一から始められて良かった。", "D": "進展していない"}},
248: {"nativeDefinition": "Too late and insufficient to make a meaningful difference.", "japaneseMeaning": "手遅れで不十分、遅すぎる", "etymology": "too little（少なすぎる）too late（遅すぎる）で、効果のない遅い対応を表す。", "examples": {"B": "謝罪は手遅れで不十分だ。もう他の人と契約を結んでいる。", "C": "誰かが亡くなってから初めて関心を示すのは残念だ。手遅れだ。今行動しないと。", "D": "遅すぎて意味がない"}},
249: {"nativeDefinition": "Everyone must help and contribute to handle a situation.", "japaneseMeaning": "総出で、全員が協力する", "etymology": "all hands on deck（全員が甲板に）という船の緊急号令に由来する。", "examples": {"B": "明日は総出で対応しないと。新製品の発売で注文数が通常の2倍になる。", "C": "今夜は総出で、このグループ課題を明日までに終わらせないと。", "D": "全員の協力"}},
250: {"nativeDefinition": "To abandon someone to face blame or danger alone.", "japaneseMeaning": "（人を）見捨てる、一人で責任を負わせる", "etymology": "洗濯物を外に干す（hang out to dry）比喩で、助けずに放置することを表す。", "examples": {"B": "多くの大学生が、将来の見通しより多くの借金を背負って自分を追い込んでいる。", "C": "見捨てられた気がする。マネージャーからはまったくサポートがなかった。", "D": "人を危険にさらして見捨てる"}},
251: {"nativeDefinition": "To be overly cautious when in doubt.", "japaneseMeaning": "慎重な方に振る、安全策を取る", "etymology": "err（誤る）on the side of caution（慎重の方に）で、迷ったら慎重にするという意味。", "examples": {"B": "サンタの存在を子どもに聞くのは親だけにすべきだと思う。他人の子どもと話すときは慎重な方に振るべきだ。", "C": "安全かどうかわからない製品を出すより、慎重な方に振るべきだ。", "D": "慎重である"}},
252: {"nativeDefinition": "In a difficult situation with no good options.", "japaneseMeaning": "板挟みだ、どちらを選んでも困る", "etymology": "岩（rock）と堅い場所（hard place）の間という比喩で、進退窮まった状況を表す。", "examples": {"B": "今板挟みだ。両親は東京に残ってほしいと言うけど、妻はカナダに移りたがっている。", "C": "板挟みだ。残業すれば彼女が怒る。残業しなければ上司が怒る。", "D": "ジレンマに陥っている"}},
253: {"nativeDefinition": "To manage to survive financially or cope with difficulties.", "japaneseMeaning": "（困難を）なんとか乗り切る、水面上に顔を出し続ける", "etymology": "水面（water）の上に頭を保つ（keep head above）という比喩。", "examples": {"B": "仕事でなんとか乗り切ろうとしているから、最近買い物する時間がほとんどない。", "C": "いくつか手伝ってくれる？今なんとか乗り切ろうとしているところなんだ。", "D": "困難に屈しない"}},
254: {"nativeDefinition": "Uncertain, weak, or not fully reliable.", "japaneseMeaning": "不安定な、自信がない", "etymology": "shaky（揺れる）で、基盤がしっかりしていない状態を表す。", "examples": {"B": "英語はまだ所々不安定だけど、だんだん良くなってきている。", "C": "初めての3Dアニメーションだ。少し不安定なのはわかっているけど、練習すれば完璧になる。", "D": "弱い"}},
255: {"nativeDefinition": "To reveal shocking or surprising news unexpectedly.", "japaneseMeaning": "爆弾発言をする、衝撃的なことを告げる", "etymology": "bombshell（爆弾）を落とす（drop）という比喩で、衝撃的なニュースを表す。", "examples": {"B": "ブレットが今朝爆弾発言をした。明日会社を辞めるらしい。", "C": "母が昨日衝撃的なことを言った。知らなかった弟がいるらしい。", "D": "思いがけないニュースを明かす"}},
256: {"nativeDefinition": "Used to clarify or emphasize what one is saying.", "japaneseMeaning": "念のため言っておくと、はっきり言っておくと", "etymology": "for the record（記録のために）で、正式に・明確に述べる前置き。", "examples": {"B": "紹介した友達、気に入った？念のため言っておくと、すごくお金持ちだけど本当に地に足がついている人だよ。", "C": "フェイスブックでこの人と話すのは楽しいんだ。念のため言っておくと、実際に会ったことはない。", "D": "知っておいてほしいことがある"}},
257: {"nativeDefinition": "To accumulate and store a large supply of something.", "japaneseMeaning": "（物を）蓄えておく、備えておく", "etymology": "stock（在庫）＋ pile（積み上げる）で、大量に蓄えることを表す。", "examples": {"B": "ここ数年、いつでも楽しめるように良いワインを蓄えてきた。", "C": "政府は企業に利益を溜め込まず投資するよう圧力をかけている。", "D": "何かを蓄える"}},
258: {"nativeDefinition": "To form an opinion based only on outward appearance.", "japaneseMeaning": "外見で判断する", "etymology": "本の表紙（cover）だけで本（book）を判断するという格言に由来。", "examples": {"B": "外見で判断するな。ギャング風に見えても、実はいい人かもしれない。", "C": "また年齢確認されるの？若く見えるけど、外見で判断しないで。実は40歳なんだ。", "D": "外見だけで判断する"}},
259: {"nativeDefinition": "Used to introduce a positive aspect amid negative news.", "japaneseMeaning": "良い点を言えば、前向きに言えば", "etymology": "positive note（前向きな点）で、否定的な話の中の明るい側面を示す表現。", "examples": {"B": "週末ずっと雨みたいだけど、良い点を言えば、もともと屋外の予定はなかったし。", "C": "一週間残業で疲れているけど、良い点を言えば、3連休が近づいている。", "D": "前向きな面を見る"}},
260: {"nativeDefinition": "To leave a place; or to become successful quickly.", "japaneseMeaning": "出発する、（売れ行きなどが）急に伸びる", "etymology": "take off（離陸する）が比喩的に、出発や急成長を表す。", "examples": {"B": "5分後に出発する。学校から子どもを迎えに行かなきゃ。", "C": "トヨタの新車は売れ行きが急伸している。発売2ヶ月で売り切れた。", "D": "出発する。好調だ。"}},
261: {"nativeDefinition": "To be given an undesirable task or outcome by chance.", "japaneseMeaning": "不運な役回りを引く、嫌な当番を引き当てる", "etymology": "短い籤（short straw）を引く（draw）というくじ引きの比喩。", "examples": {"B": "今回は本当に不運な役回りを引いた。3日連続で夜勤だ。", "C": "厳しい面接官との面接を引き当てた。難しい質問を浴びせられた。", "D": "不運である"}},
262: {"nativeDefinition": "To vent frustration on someone who is not responsible.", "japaneseMeaning": "（八つ当たりで）人に当たる", "etymology": "take it out on（〜にぶつける）で、感情を無関係な人に向けることを表す。", "examples": {"B": "部下に八つ当たりするのはやめて。職場の士気に良くない。", "C": "ご不便をおかけして申し訳ないですが、配送の問題は私のせいではありません。八つ当たりしないでください。", "D": "人に感情をぶつける"}},
263: {"nativeDefinition": "To examine something very thoroughly and in detail.", "japaneseMeaning": "（細部まで）徹底的に調べる", "etymology": "fine-tooth comb（細かい歯の櫛）で梳かすように、細部まで調べることを表す。", "examples": {"B": "レポート提出後は変更できない。提出前に細部まで徹底的に確認して。", "C": "ジョンが財務諸表を細部まで徹底的に調べている。", "D": "何かを詳しく検討する"}},
264: {"nativeDefinition": "To have complete freedom to act as one wishes.", "japaneseMeaning": "自由にやらせる、思う存分やらせる", "etymology": "rein（手綱）を自由にする（free）という比喩で、制限なく行動できることを表す。", "examples": {"B": "美容師を信頼しているから、髪の色は自由にやらせた。結果は鮮やかな緑だった。まあいいけど。", "C": "妻には食事の場所を自由に決めさせている。僕は何でもいいから。", "D": "完全な自由を持つ"}},
265: {"nativeDefinition": "To delay or postpone doing something.", "japaneseMeaning": "（何かを）控える、先延ばしにする", "etymology": "hold off（控える）on（〜について）で、行動を遅らせることを表す。", "examples": {"B": "質問を控える必要はない。バカな質問なんてないんだから。", "C": "ピーターにパイの焼き始めを控えてもらえる？今そんなに食べ物が要るかわからない。", "D": "何かを延期する"}},
266: {"nativeDefinition": "Uninformed or unaware about something.", "japaneseMeaning": "（事情を）知らされていない、暗闇の中にいる", "etymology": "in the dark（暗闇の中）で、情報を与えられていない状態を表す。", "examples": {"B": "彼女がなぜ2つのLINEアカウントを持っているのかわからない。不安になってきた。", "C": "政府は首相が米大統領と何を話したか、国民に知らせようとしていない。", "D": "知らされていない"}},
267: {"nativeDefinition": "To analyze and explain something in detail.", "japaneseMeaning": "（概念などを）詳しく分析する、掘り下げる", "etymology": "unpack（荷ほどきする）が比喩的に、複雑な内容を分解して説明することを表す。", "examples": {"B": "ベーシックインカムは掘り下げることがたくさんある魅力的なテーマだ。", "C": "この概念を掘り下げさせて。かなり複雑だから。", "D": "何かを分解して分析する"}},
268: {"nativeDefinition": "Wait; slow down and be patient.", "japaneseMeaning": "ちょっと待って、焦らないで", "etymology": "hold your horses（馬を抑えろ）という昔の表現で、急がないで待てという意味。", "examples": {"B": "全財産を株に突っ込もうとしていたけど、ファイナンシャルアドバイザーに焦らないでと言われた。", "C": "え、待って。同じ高校だったの？話したことなかったよね？", "D": "待つ"}},
269: {"nativeDefinition": "To do something unpleasant quickly so it is finished.", "japaneseMeaning": "（嫌なことを）さっさと終わらせる", "etymology": "get it over with（それを終わらせる）で、不快なことを早く片付けることを表す。", "examples": {"B": "親知らずを抜いてさっさと終わらせるつもりだ。ずっと邪魔になっている。", "C": "あの人に会いに行ってさっさと終わらせよう。今日以降は会いたくない。", "D": "さっと片付ける"}},
270: {"nativeDefinition": "Convinced or persuaded about something.", "japaneseMeaning": "（〜に）納得している、説得されている", "etymology": "sold（売られた）on（〜に）で、説得されて賛成している状態を表す。", "examples": {"B": "必要なスキルと知識は全部揃っているけど、彼の人柄にはまだ納得していない。", "C": "この広告の言うことには納得していない。初心者が2週間で英語が流暢になるなんてあり得る？", "D": "何かに納得している"}},
271: {"nativeDefinition": "To fail under pressure at a critical moment.", "japaneseMeaning": "（重圧で）失敗する、肝心な場面でミスする", "etymology": "choke（息が詰まる）が比喩的に、緊張で力を発揮できなくなることを表す。", "examples": {"B": "ゴール直前でミスするからレースに勝てない。", "C": "クリスティアーノは得点チャンスでミスしないからたくさんゴールを決める。", "D": "プレッシャーに負ける"}},
272: {"nativeDefinition": "Fear of missing out on experiences or social events.", "japaneseMeaning": "取り残される恐怖、見逃す不安", "etymology": "Fear Of Missing Out の頭文字。見逃すことへの不安を表す現代の造語。", "examples": {"B": "研究によると、取り残される恐怖はソーシャルメディア依存の最大の原因の一つだ。", "C": "パーティーに行きたくなかったけど、見逃す不安があって結局行った。", "D": "取り残されることへの恐れ"}},
273: {"nativeDefinition": "To change one's mind or decision.", "japaneseMeaning": "考えを変える、気が変わる", "etymology": "change of heart（心の変化）で、決意や考えが変わることを表す。", "examples": {"B": "もう遅い。結婚式の招待状の色はデザイナーに伝えてしまった。", "C": "気が変わって、仕事を辞めて世界一周旅行に出ることにした。上の人たちはあまり喜ばなかった。", "D": "考えを変える"}},
274: {"nativeDefinition": "To flatter someone in order to gain favor.", "japaneseMeaning": "（人に）媚びへつらう、ご機嫌取りをする", "etymology": "suck up（吸い上げる）が比喩的に、おべっかを使うことを表す。", "examples": {"B": "ネオジが上司に媚びへつらっているのは丸わかりだ。他の人にはそんなに優しくない。", "C": "要するに、その記事は日本の首相が米大統領に媚びへつらうのが好きだと書いていた。", "D": "人に媚びへつらう"}},
275: {"nativeDefinition": "A simple, magical solution to a complex problem.", "japaneseMeaning": "特効薬、簡単な解決策", "etymology": "silver bullet（銀の弾丸）が狼人間伝説から、複雑な問題の簡単な解決策を表す。", "examples": {"B": "地球温暖化を解決する特効薬はない。空中から何かを引っこ抜くわけにはいかない。", "C": "日本の人口減少に特効薬はない。複雑な問題には複雑な政策が必要だ。", "D": "魔法のような解決策"}},
276: {"nativeDefinition": "A person who loves reading books.", "japaneseMeaning": "本の虫、読書好き", "etymology": "book（本）＋ worm（虫）で、本を食べる虫のように読書が好きな人を表す。", "examples": {"B": "読書好きの友達は最高だ。文学の知識を披露したがるから、会話するだけでたくさん学べる。", "C": "彼みたいな読書好きには、この電子書籍リーダーが最高の誕生日プレゼントだと思う。", "D": "本好き"}},
277: {"nativeDefinition": "To risk everything and use maximum effort.", "japaneseMeaning": "思い切って全力を出す、背水の陣でやる", "etymology": "go for broke（破産するまで行く）で、全てを賭けて全力を出すことを表す。", "examples": {"B": "来週までにこの宿題を終わらせるために思い切って全力を出すつもりだ。", "C": "このプロジェクトは重要だから、背水の陣でやらないといけない。", "D": "最大限の努力や資源を使う"}},
278: {"nativeDefinition": "Something one is particularly good at.", "japaneseMeaning": "得意分野、強み", "etymology": "strong suit（強いスート）がトランプ用語から、得意な分野を表すようになった。", "examples": {"B": "文法のことは聞かないで。僕の得意分野じゃない。", "C": "会計は本当に苦手だ。絶対に得意分野じゃない。", "D": "強み"}},
279: {"nativeDefinition": "To ask someone for advice or information based on their expertise.", "japaneseMeaning": "（人の）知恵を借りる、意見を聞く", "etymology": "pick（摘む）someone's brain（脳）で、知識や経験を引き出すことを表す。", "examples": {"B": "この数学の問題について知恵を借りてもいい？君はこの分野の専門家だから。", "C": "コンサル会社に頼まないで。知恵を借りると言っても、いつも法外な料金を請求される。", "D": "人に助言を求める"}},
280: {"nativeDefinition": "Done perfectly according to standard technique; exemplary.", "japaneseMeaning": "教科書通りの、模範的な", "etymology": "textbook（教科書）が形容詞的に、教科書に載っているほど完璧なことを表す。", "examples": {"B": "あれはまさに教科書通りのフリーキックだった。マッシーは本当に繊細なタッチを持っている。", "C": "あのスラムダンクは教科書通りだった。", "D": "完璧な"}},
281: {"nativeDefinition": "People have different preferences and that is acceptable.", "japaneseMeaning": "人それぞれだ、好みは十人十色", "etymology": "each their own（それぞれ自分のもの）で、個人の好みの違いを認める表現。", "examples": {"B": "コリアンダーが嫌いなの？僕にとっては世界最高のハーブだけど、まあ人それぞれだね。", "C": "同じ会社で10年以上働くなんて考えられないけど、人それぞれだよね。", "D": "人にはそれぞれ好みがある"}},
282: {"nativeDefinition": "To avoid embarrassment or loss of dignity.", "japaneseMeaning": "面子を保つ", "etymology": "face（顔・面子）をsave（守る）するという中国文化圏由来の表現。", "examples": {"B": "クリスが面子を保つのはもう遅い。みんな彼が失敗したことを知っている。", "C": "ディナーに顔を出さないと面子が保てない。前回は欠席したから。", "D": "恥を避ける"}},
283: {"nativeDefinition": "To support or endorse something.", "japaneseMeaning": "（計画などを）支持する、後押しする", "etymology": "get behind（後ろについて）で、陰から支える＝支持することを表す。", "examples": {"B": "今夜はチームをしっかり支持しよう。観客が前向きだとずっと良いプレーをする。", "C": "ジェームズがこのプロジェクトを支持してくれているのは本当に良いことだ。大きな助けになっている。", "D": "何かを支持する"}},
284: {"nativeDefinition": "As the situation currently stands.", "japaneseMeaning": "現状では、今のところ", "etymology": "as it stands（それが立っているまま）で、現在の状況をそのまま述べる表現。", "examples": {"B": "現状ではランチに行けない。仕事が忙しそうだ。", "C": "現状では来年新しい車は買えない。", "D": "現在の状況を考えると"}},
285: {"nativeDefinition": "To expand one's knowledge, experience, or perspective.", "japaneseMeaning": "視野を広げる", "etymology": "horizons（地平線）をbroaden（広げる）という比喩的な表現。", "examples": {"B": "留学して視野を広げるべきだ。", "C": "大学は様々な背景の人に出会い、視野を広げる素晴らしい機会だ。", "D": "見解を広げる"}},
286: {"nativeDefinition": "Unable to control one's behavior or impulses.", "japaneseMeaning": "（自分を）抑えられない", "etymology": "can't help oneself（自分を助けられない）で、衝動を抑えられないことを表す。", "examples": {"B": "デザートの前では自分を抑えられない。本当に大好きなんだ。", "C": "メーガンは自分を抑えられない。計画通りにいかないと何でも批判しなきゃいけない。", "D": "自分をコントロールできない"}},
287: {"nativeDefinition": "Extremely happy and delighted.", "japaneseMeaning": "有頂天だ、大喜びだ", "etymology": "over the moon（月の上）で、月まで飛び上がるほど嬉しいことを表すイギリス英語。", "examples": {"B": "クリスマスに新しいスマホをもらって有頂天だ。友達からこんな高いものをもらうとは思わなかった。", "C": "昨夜一緒に過ごせて本当に有頂天だ。", "D": "とても幸せ"}},
288: {"nativeDefinition": "Please tell me again; I have forgotten.", "japaneseMeaning": "もう一度教えて、思い出させて", "etymology": "remind me again（もう一度思い出させて）で、忘れたことを再度教えてほしいという依頼。", "examples": {"B": "もう一度教えて、ここから家への帰り方は？すごく酔っ払っている。", "C": "昨日の会議で何を扱ったか、もう一度教えてくれる？実は半分寝ていた。", "D": "記憶をよみがえらせる"}},
289: {"nativeDefinition": "To progress through something awkwardly and with difficulty.", "japaneseMeaning": "（何かを）ぎこちなく進める、なんとかこなす", "etymology": "stumble（つまずく）one's way through で、ぎこちなく進むことを表す。", "examples": {"B": "フィルはスピーチをぎこちなく進めた。練習していなかったのが明らかだった。", "C": "日本語を学ぶのが楽しみだったけど、初級の授業をなんとかこなして、すぐに諦めた。", "D": "ぎこちなく何かを進める"}},
290: {"nativeDefinition": "Feeling anxious and prone to panic.", "japaneseMeaning": "あわてやすい、落ち着きがない", "etymology": "panic（パニック）＋ -y（〜しやすい）で、不安でパニックになりやすいことを表す。", "examples": {"B": "サムは人前でプレゼンすると少しパニックになりやすい。", "C": "仕事の不安定さで少しパニックになりやすくなっている。夜眠れない。", "D": "神経質で不安な"}},
291: {"nativeDefinition": "Unfair and cruel, especially in a personal attack.", "japaneseMeaning": "卑劣な、公平ではない", "etymology": "ボクシングのベルト（belt）より下を打つ（below）＝ルール違反の卑劣な攻撃という比喩。", "examples": {"B": "「いつ結婚するの？」みたいな質問は、本当に卑劣だ。", "C": "ずっと前のミスについて謝ったのに、みんなの前で蒸し返すのは卑劣じゃない？", "D": "残酷で不公平な"}},
292: {"nativeDefinition": "Extremely rare and unique.", "japaneseMeaning": "百万に一つの、非常に稀な", "etymology": "one in a million（100万分の1）で、極めて稀で特別なことを表す。", "examples": {"B": "彼女が百万に一つで他にいないなんて本気で思ってるの？世界の人口は70億だよ。", "C": "この新曲がヒットする確率は百万に一つだ。", "D": "独特で、ありそうもない"}},
293: {"nativeDefinition": "Something memorable and worth experiencing, often unusual.", "japaneseMeaning": "（一度は）経験する価値のあること、思い出に残る体験", "etymology": "an experience（一つの経験）で、特別で記憶に残る体験を表す。", "examples": {"B": "高校生のとき、よくマクドナルドで夜遅くまで勉強した。いい思い出だ。", "C": "バンジージャンプはどうだった？一度は経験する価値はあるけど、もう二度とやらないかな。", "D": "面白い経験"}},
294: {"nativeDefinition": "To achieve two goals with a single action.", "japaneseMeaning": "一石二鳥だ", "etymology": "一つの石（one stone）で二羽の鳥（two birds）を殺すという比喩。", "examples": {"B": "自転車通勤は一石二鳥だ。健康維持にもなるし、通勤にもなる。", "C": "トレッドミルの上で読書するのが好きだ。一石二鳥だ。", "D": "一つの行動で二つのことを成し遂げる"}},
295: {"nativeDefinition": "To cancel or terminate something.", "japaneseMeaning": "（計画などを）中止する、打ち切る", "etymology": "pull the plug（プラグを抜く）で、電源を切るように中止することを表す。", "examples": {"B": "あのドラマが打ち切りになるなんて信じられない。2シーズンしか経ってないのに、すごく良かったのに。", "C": "ごめん、今日のランチは中止しないと。体調が少し悪い。", "D": "中止する"}},
296: {"nativeDefinition": "Past events that are no longer worth worrying about.", "japaneseMeaning": "過ぎ去ったこと、水に流す", "etymology": "橋の下を流れる水（water under the bridge）という比喩で、過去の出来事を表す。", "examples": {"B": "もう怒っていない。ずっと前のことだから。水に流した。", "C": "6ヶ月前に別れた。もう水に流した。", "D": "すべて過去のこと"}},
297: {"nativeDefinition": "The most important or dominant person in a group.", "japaneseMeaning": "筆頭だ、一番偉い人", "etymology": "top（頂点）dog（犬）で、群れの中で最も偉い存在を表す。", "examples": {"B": "ニックをあまり怒らせないようにしよう。ここでは彼がトップだ。", "C": "彼女がトップだと思っているだけで、実際には誰も彼女の言うことを聞いていない。", "D": "最も重要な人"}},
298: {"nativeDefinition": "Silence or lack of news suggests nothing bad has happened.", "japaneseMeaning": "便りがないのは良い知らせだ", "etymology": "news（知らせ）がない（no）はgood news（良い知らせ）という逆説的な表現。", "examples": {"B": "クレジットカード会社から何も連絡がない。便りがないのは良い知らせだよね？", "C": "CEOはリストラについて何も言っていない。便りがないのは良い知らせだと思う。", "D": "何も聞かないことは、悪いことが起きていないことを示す"}},
299: {"nativeDefinition": "To attract stares or attention from people.", "japaneseMeaning": "（人から）視線を集める、じろじろ見られる", "etymology": "get looks（視線をもらう）from people で、人々の注目を集めることを表す。", "examples": {"B": "日本で英語を話すと人からジロジロ見られるかもしれないけど、学ぶには最善の方法だ。", "C": "そのTシャツを本当に着ていくの？確かに人からジロジロ見られるよ。", "D": "人にじっと見られる"}},
300: {"nativeDefinition": "Something that is certain to succeed.", "japaneseMeaning": "確実な成功、決まりだ", "etymology": "バスケのダンクシュート（slam dunk）が確実に決まることから、確実な成功を表す。", "examples": {"B": "彼女がプロポーズを受け入れるのは確実だと思っていたけど、現実は厳しい。", "C": "面接官は僕のことが気に入っているようだから、この仕事はもう決まりだと思う。", "D": "確実な成功"}},
301: {"nativeDefinition": "To categorize someone or something narrowly and restrictively.", "japaneseMeaning": "（人を）型にはめる、特定の枠に当てはめる", "etymology": "pigeonhole（鳩の巣箱）に入れる比喩で、狭いカテゴリーに分類することを表す。", "examples": {"B": "大学で会計を学んだけど、キャリアの早い段階で型にはめたくなかったから、YouTubeチャンネルを始めた。", "C": "喫煙率が下がっている今、タバコ会社だけと決めつけられないよう製品を多様化することが重要だ。", "D": "人を制限的なカテゴリーに入れる"}},
302: {"nativeDefinition": "A feeling of calm and freedom from worry.", "japaneseMeaning": "安心感、心の平穏", "etymology": "peace（平和）of mind（心）で、心の安らぎを表す。", "examples": {"B": "健康保険は安心感をくれる。何かあったとき、経済的に守られているとわかっている。", "C": "アプリから家の中を見られる監視カメラを買った。必要ないかもしれないけど、安心のために。", "D": "安心感"}},
303: {"nativeDefinition": "Used to accept an unfortunate but unchangeable outcome.", "japaneseMeaning": "そういうものだ、仕方ない", "etymology": "クッキーが崩れる（crumble）ように物事は思い通りにならないという比喩。", "examples": {"B": "今朝頭に鳥のフンが落ちたのは嫌だけど、そういうものだ。", "C": "先週脱毛したのに、気になる子は毛深い顔が好きだと知った。そういうものだ。", "D": "残念ながら、時々そういうことは起きる"}},
304: {"nativeDefinition": "To start something that causes unforeseen problems.", "japaneseMeaning": "（問題を招く）災いの箱を開ける", "etymology": "ギリシャ神話のパンドラの箱から、取り返しのつかない問題を招くことを表す。", "examples": {"B": "AIには多くの利益があると思うけど、武器化AIの脅威が心配だ。一度このパンドラの箱を開けたら、閉じるのは難しい。", "C": "息子の英語のテストの良い点に報酬を出したら、パンドラの箱を開けてしまった。今は何をするにも報酬を求める。", "D": "問題につながることを始める"}},
305: {"nativeDefinition": "Very welcome or pleasing news.", "japaneseMeaning": "聞いてうれしい話、耳に心地よい", "etymology": "music to my ears（耳に音楽）で、聞いて嬉しいことを表す。", "examples": {"B": "親友からオックスフォード大学に合格したとメッセージが来た。聞いてうれしい話だ。", "C": "ベンが新製品がよく売れていると言ってくれた。耳に心地よい話だ。", "D": "素晴らしい知らせ"}},
306: {"nativeDefinition": "To show off or perform in an attention-seeking way.", "japaneseMeaning": "見せびらかす、派手にやる", "etymology": "showboat（見世物船）から、注目を集めるために派手に振る舞うことを表す。", "examples": {"B": "5対0で勝っていたのに、見せびらかし始めて6点取られて負けた。バカじゃない？", "C": "ボクサーがガードを下ろして見せびらかしたら、ノックアウトされた。", "D": "見せびらかす"}},
307: {"nativeDefinition": "To begin to develop a clear and definite form.", "japaneseMeaning": "（計画などが）形になってくる", "etymology": "take shape（形を取る）で、漠然としたものが具体化することを表す。", "examples": {"B": "8時間アイデアを出し合った後、やっと計画が形になってきた。", "C": "何度も試行錯誤した後、ようやくビジョンが形になった。失敗を恐れず挑戦し続けることだ。", "D": "明確な形になる"}},
308: {"nativeDefinition": "To address the most important or central issue.", "japaneseMeaning": "問題の核心に迫る", "etymology": "heart（心臓・核心）of the matter（問題）に到達する（get to）という比喩。", "examples": {"B": "問題の核心に迫る才能は本当にすごい。あの人みたいになりたい。", "C": "政治家たちは的外れな質問ばかりして、問題の核心に迫らない。本当にイライラする。", "D": "最も重要な問題に取り組む"}},
309: {"nativeDefinition": "To analyze or present data from multiple perspectives.", "japaneseMeaning": "（数値などを）様々な切り口で分析する", "etymology": "cut（切る）in many different ways で、多角的に切り分けることを表す。", "examples": {"B": "ビジネスをどう見たいかによって、財務データを様々な切り口で分析できる。", "C": "語学学習は文法、語彙、発音など、様々な切り口で分けられる。", "D": "様々な方法で何かを解釈する"}},
310: {"nativeDefinition": "Perfect in appearance; ideally beautiful.", "japaneseMeaning": "絵に描いたような、完璧な", "etymology": "picture（絵）perfect（完璧な）で、写真のように完璧な美しさを表す。", "examples": {"B": "このサイトで絵に描いたようなホテルを見つけた。今すぐ予約しよう。", "C": "アメリカには、父と母と子どもたちと大きな家という典型的な絵に描いたような家族像がある。アメリカンドリームと呼ばれる。", "D": "理想的な"}},
311: {"nativeDefinition": "To make someone extremely angry.", "japaneseMeaning": "（人を）激怒させる", "etymology": "blood boil（血が沸く）という比喩で、激しい怒りを表す。", "examples": {"B": "母が今朝5時に起こしてきた。本当に激怒した。今日は日曜日だよ！", "C": "もうずいぶん待っている。なぜ客を対応しているのが一人だけなのかわからない。本当にイライラする。", "D": "人を非常に怒らせる"}},
312: {"nativeDefinition": "To be easy and pleasant to say or pronounce.", "japaneseMeaning": "（言葉が）口にしやすい、言いやすい", "etymology": "roll off the tongue（舌から転がり落ちる）で、滑らかに発音できることを表す。", "examples": {"B": "会社名をつけるときは、口にしやすい名前にすべきだ。将来の人気に影響する。", "C": "squirrel、squirrel、squirrel。うわ、この単語きつい。全然口にしやすくない。", "D": "言いやすい"}},
313: {"nativeDefinition": "No resentment or hard feelings remain.", "japaneseMeaning": "恨みはない、気にしていない", "etymology": "hard feelings（強い感情・恨み）がない（no）という意味。", "examples": {"B": "足を骨折させて謝り、入院費も払ったから、恨みはないでしょ？", "C": "何度も謝らなくていいよ。大丈夫、気にしてない。", "D": "恨みはない"}},
314: {"nativeDefinition": "To make a bad situation worse for someone already suffering.", "japaneseMeaning": "（落ち目の人を）追い打ちをかける", "etymology": "ボクシングで倒れた相手をベルト以下に打つ（below the belt）＝卑劣な追い打ちの比喩。", "examples": {"B": "現在の経済状況で税率を上げるのは、消費者に追い打ちをかけるようなものだ。", "C": "意地悪なマネージャーらしい。落ち目の人に追い打ちをかける。", "D": "困っている人の状況をさらに悪くする"}},
315: {"nativeDefinition": "To continue despite difficulties.", "japaneseMeaning": "（困難を）乗り越えて続ける、踏ん張る", "etymology": "soldier on（兵士のように進む）で、逆境の中でも続けることを表す。", "examples": {"B": "試験中は手首を捻挫していて全力は出せなかったけど、踏ん張って続けた。", "C": "チームメンバーが一人足りないのはわかっているけど、踏ん張って続けるしかない。", "D": "逆境の中でも前に進む"}},
316: {"nativeDefinition": "To diminish the value or significance of something.", "japaneseMeaning": "（価値を）損なう、目立たなくする", "etymology": "take away from（〜から取り去る）で、価値や意義を減らすことを表す。", "examples": {"B": "彼の功績を貶めるつもりはないけど、全部一人でやったなんて言うのはおかしい。明らかに助けてもらっていた。", "C": "他人が早くフォロワーを増やすのを妬まないで。他人の成功は自分の価値を損なわない。", "D": "何かの価値を損なう"}},
317: {"nativeDefinition": "To be absolutely certain about something.", "japaneseMeaning": "（何かを）絶対に確信する、家を賭けてもいい", "etymology": "bet one's house（家を賭ける）で、全財産を賭けるほど確信していることを表す。", "examples": {"B": "この賞は絶対に取れると家を賭けてもいい。裏でコネを使ったから。", "C": "この動画を見たら笑うと家を賭けてもいい。友達が送ってきたし、彼女は良い動画を見抜く目がある。", "D": "何かを保証する"}},
318: {"nativeDefinition": "An excessively large number of people.", "japaneseMeaning": "誰も彼も、ごく普通の人たち", "etymology": "every man and his dog（すべての男とその犬）で、ありふれた大勢の人々を表す。", "examples": {"B": "誰も彼も断捨離ブームに乗っているからといって、君もやる義務があるわけじゃない。", "C": "最近は誰も彼も海外で働いているから、僕も考えた方がいいかも。", "D": "非常に多くの人"}},
319: {"nativeDefinition": "To be in a subordinate or less important role.", "japaneseMeaning": "（人の）脇役に回る、二番手になる", "etymology": "play second fiddle（第二バイオリンを弾く）で、主役の陰に回ることを表す。", "examples": {"B": "マークと同じくらい能力があるのに、なぜいつも彼の脇役に回らなきゃいけないのかわからない。", "C": "スチュアートがクリスの脇役に甘んじているなんて信じられない。二人のうち明らかに彼の方が才能がある。", "D": "誰かより重要度が低く扱われる"}},
320: {"nativeDefinition": "To act with minimal personal risk because the stake is not one's own.", "japaneseMeaning": "他人の金で勝負する、損失の心配なくやる", "etymology": "house money（カジノのハウスマネー）で遊ぶように、失っても痛くない状況を表す。", "examples": {"B": "売っているバッグは無料でもらったものだから、他人の金で勝負しているようなものだ。", "C": "ソッキーは今他人の金で勝負している状態だ。どの箱を選んでも賞品がもらえる。", "D": "最小限のリスクでやる"}},
321: {"nativeDefinition": "An unavoidable aspect of life.", "japaneseMeaning": "人生の常、避けられないこと", "etymology": "fact of life（人生の事実）で、受け入れるしかない現実を表す。", "examples": {"B": "税金はみんな払わなきゃいけない。それが人生の常だ。", "C": "新しい友達を作り、古い友達を失うのは人生の常だ。", "D": "避けられないこと"}},
322: {"nativeDefinition": "Very common and not special.", "japaneseMeaning": "ありふれている、ごく普通", "etymology": "a dime a dozen（10セントで12個）で、安くて大量にある＝ありふれていることを表す。", "examples": {"B": "インスタでフォロワー1万人以上の人は今やありふれている。", "C": "良いアイデアはありふれているが、アイデアを実行に移す人は貴重だ。", "D": "非常にありふれている"}},
323: {"nativeDefinition": "An obvious but unaddressed problem everyone avoids discussing.", "japaneseMeaning": "誰もが知っているが言えない問題、部屋の象", "etymology": "部屋の中の象（elephant in the room）という比喩で、誰も触れない明白な問題を表す。", "examples": {"B": "従業員を一人解雇しなければならない。これが部屋の象だとわかっているけど、残念ながら必要なんだ。", "C": "教育と高低所得者間の平等が、誰もが知っているが言えない問題だ。", "D": "デリケートな話題"}},
324: {"nativeDefinition": "Very rare; not occurring often.", "japaneseMeaning": "稀だ、めったにない", "etymology": "few and far between（少なくて離れている）で、めったにないことを表す。", "examples": {"B": "ゲームセンターはアメリカではめったにないが、日本ではまだ盛んだ。", "C": "リックのような人はめったにいない。真実を語り、遠慮がなく、甘い言葉も使わない。", "D": "非常に稀な"}},
325: {"nativeDefinition": "Without showing amusement; with a serious expression.", "japaneseMeaning": "真顔で、平然と", "etymology": "straight face（真顔）で、感情を表に出さずに話すことを表す。", "examples": {"B": "ジョンはプロフィール写真にいいねがついただけで「もうほぼモデルだ」と真顔で言った。なぜまだここにいるのかわからない。", "C": "5回連続で失敗した直後に、確実に女の子を口説く方法を知っていると真顔で言えるの？", "D": "真面目な様子で"}},
326: {"nativeDefinition": "To begin behaving in an uncontrolled or erratic way.", "japaneseMeaning": "（行動が）脱線する、道を踏み外す", "etymology": "go off the rails（線路から外れる）で、正常な行動から逸脱することを表す。", "examples": {"B": "ジョージは金魚が死んでから少しの間、行動が脱線した。かなり落ち込んでいたんだと思う。", "C": "有望な学生が薬物中毒者と付き合い始めて、道を踏み外した。", "D": "常軌を逸した行動をする"}},
327: {"nativeDefinition": "Very rarely; almost never.", "japaneseMeaning": "めったにない、月に一度あるかないか", "etymology": "once in a blue moon（青い月に一度）で、非常に稀なことを表す。", "examples": {"B": "フェデラーが負けるのはめったにない。戦績が物語っている。", "C": "ニュージーランドでは電車が定時に来るのはめったにない。日本ではほとんどの場合定時だ。", "D": "非常に稀に"}},
328: {"nativeDefinition": "Things are going well so far.", "japaneseMeaning": "今のところ順調だ", "etymology": "so far（これまで）so good（良い）で、現時点では問題ないことを表す。", "examples": {"B": "新しいドラマを見始めたばかりだけど、今のところ順調だ。この女優への憧れがリアルすぎる。", "C": "新しい仕事は今のところ順調だけど、まだ理解しきれていないことがいくつかある。", "D": "ここまでは順調"}},
329: {"nativeDefinition": "Unable to find words to express one's feelings.", "japaneseMeaning": "言葉が出ない、言葉に詰まる", "etymology": "at a loss for words（言葉に困る）で、驚きや感動で言葉が出ないことを表す。", "examples": {"B": "彼女に今年5回目財布をなくしたと言ったら、言葉に詰まっていた。", "C": "この映画の素晴らしさには言葉が出ない。ストーリーがどんどん引き込まれる。", "D": "言葉が出ない"}},
330: {"nativeDefinition": "A backup plan or protection against risk.", "japaneseMeaning": "安全網、万が一の備え", "etymology": "safety net（安全網）が比喩的に、失敗時の保護を表す。", "examples": {"B": "電車で隣の男が電話で「彼女が僕の安全網なんだ、本人は知らないけど」と言っていた。こういう人は寒い。", "C": "パソコンのハードドライブが故障したときのために、クラウドストレージが安全網だ。あれば安心。", "D": "リスク軽減策"}},
331: {"nativeDefinition": "A harsh environment where one must succeed or fail on their own.", "japaneseMeaning": "自力で生き残るか沈むか、厳しい環境", "etymology": "sink or swim（沈むか泳ぐか）で、助けなしに自力で乗り切る環境を表す。", "examples": {"B": "前の会社を辞めたのは、自力で生き残るか沈むかの環境だったから。同じレベルに2年以上留まることを許さなかった。", "C": "多くの国が50年間アメリカ資本主義を模倣し、同じような厳しく不平等な社会になっている。", "D": "容赦ない"}},
332: {"nativeDefinition": "To suddenly become too nervous to proceed.", "japaneseMeaning": "（不安になって）尻込みする", "etymology": "get cold feet（冷たい足になる）で、結婚前の不安から、尻込みすることを表す。", "examples": {"B": "かわいい子がデートに乗り気だったのに、すっぽかされた。尻込みしたんだろう。", "C": "昨日バンジージャンプに行くつもりだったけど、橋の上で尻込みした。狂ってる。", "D": "急に不安になりすぎる"}},
333: {"nativeDefinition": "To take attention away from someone else's moment.", "japaneseMeaning": "（人の）注目を奪う、花形の座を奪う", "etymology": "steal someone's thunder（雷を盗む）という19世紀の逸話に由来する表現。", "examples": {"B": "サムスンが発売した新フラッグシップは、新しいiPhoneの注目を奪うだろう。", "C": "ブライズメイドが派手すぎると、花嫁の注目を奪うのが心配だ。", "D": "人から注目を奪う"}},
334: {"nativeDefinition": "In control of a situation.", "japaneseMeaning": "主導権を握っている、運転席にいる", "etymology": "driver's seat（運転席）にいる（in）で、状況をコントロールしていることを表す。", "examples": {"B": "バルセロナが5点リードして主導権を握っている。ダビデ対ゴリアテの試合だ。", "C": "指示に従うのはあまり好きじゃない。主導権を握っていたい。", "D": "コントロールしている"}},
335: {"nativeDefinition": "Unusual or different from what is normal.", "japaneseMeaning": "普通ではない、いつもと違う", "etymology": "out of the ordinary（普通の外）で、通常と異なることを表す。", "examples": {"B": "大きなアニメステッカーのついたピンクの車は、ちょっと普通じゃないね。", "C": "この寿司屋が好きなんだ。特別なわけじゃないけど、雰囲気が最高なんだ。", "D": "普通ではない"}},
336: {"nativeDefinition": "A short speech intended to motivate or encourage.", "japaneseMeaning": "激励の言葉、気合いを入れる話", "etymology": "pep（元気）＋ talk（話）で、やる気を起こさせる短いスピーチを表す。", "examples": {"B": "やる気が出ないとき、いつも自分に激励の言葉をかける。意外と効果的だ。", "C": "チームはずっと負け続けて全員ストレスを感じていた。コーチが「心配するな、忍耐強く、できる」と激励してくれた。", "D": "短い激励のスピーチ"}},
337: {"nativeDefinition": "To understand the current situation or environment.", "japaneseMeaning": "（状況を）把握する、様子を見る", "etymology": "lay of the land（土地の起伏）で、周囲の状況を把握することを表す。", "examples": {"B": "ディズニーがストリーミングサービスを始めるのか。状況を把握するために調べるけど、たぶん契約する。", "C": "今日新しいプロジェクトチームと会って状況を把握し、今後数週間の計画を立てる。", "D": "背景を理解する"}},
338: {"nativeDefinition": "To pursue the wrong course or approach.", "japaneseMeaning": "見当違いだ、方向が違う", "etymology": "barking up the wrong tree（間違った木に吠える）という狩猟の比喩。", "examples": {"B": "政治家がビデオゲームが犯罪を増やすと言っていたけど、見当違いだと思う。", "C": "IT関連の質問？だったら見当違いだよ。僕は清掃員だ。", "D": "方向や考え方が完全に間違っている"}},
339: {"nativeDefinition": "Something that keeps changing and is hard to target.", "japaneseMeaning": "動く的、変化し続ける目標", "etymology": "moving target（動く標的）で、捉えにくい変化する対象を表す。", "examples": {"B": "ビジネス課題の解決は動く的を狙うようなものだから、戦略は柔軟でなければならない。", "C": "人間の欲求は動く的だ。マズローの欲求階層説がそれをよく説明している。", "D": "常に動き続けるもの"}},
340: {"nativeDefinition": "Speed and timeliness are critical.", "japaneseMeaning": "時間が重要だ、急がなければならない", "etymology": "time is of the essence（時間が本質である）という法律用語から、時間の重要性を表す。", "examples": {"B": "時間が命だ。今すぐ夢に向かって動き出せ。足踏みしていられない。", "C": "時間が命だから、このプロジェクトにサボる人はいられない。", "D": "スピードが重要"}},
341: {"nativeDefinition": "To openly show one's emotions.", "japaneseMeaning": "感情を表に出す、素直に気持ちを見せる", "etymology": "wear one's heart on one's sleeve（袖に心を着ける）というシェイクスピア由来の表現。", "examples": {"B": "職場では感情を表に出さない。意味がないし、プロフェッショナルじゃないから。", "C": "ジミーが不機嫌かどうかはいつもわかる。感情を表に出している。", "D": "感情をはっきり表に出す"}},
342: {"nativeDefinition": "Nervous, anxious, and easily upset.", "japaneseMeaning": "神経質な、すぐ緊張する", "etymology": "highly strung（高く張られた）で、弦が張り詰めたように神経質なことを表す。", "examples": {"B": "今日は母の周りで大きな音を立てない方がいい。かなり神経質なんだ。", "C": "先週の爆弾脅迫のせいで、スタジアムの警備員は今かなり神経質だ。", "D": "神経質な"}},
343: {"nativeDefinition": "Very expensive.", "japaneseMeaning": "とても高い、法外な値段だ", "etymology": "an arm and a leg（腕と脚）をcost（費やす）という比喩で、非常に高価なことを表す。", "examples": {"B": "法外な値段のかからないiPhone用動画編集アプリ、誰かおすすめある？", "C": "ついに初めてのロレックスを手に入れた。法外な値段だったけど、大好きだ。", "D": "とても高い"}},
344: {"nativeDefinition": "To remain uncertain until the very end.", "japaneseMeaning": "最後までわからない、ぎりぎりまで決まらない", "etymology": "down to the wire（最後のワイヤーまで）が競馬用語から、最後まで勝負がつかないことを表す。", "examples": {"B": "今年の業績は最後までわからない。", "C": "昨夜のバスケの試合は最後までわからなかった。本当に楽しかった。", "D": "最後まで不確実"}},
345: {"nativeDefinition": "To suffer embarrassment or loss of dignity.", "japaneseMeaning": "面子を失う、恥をかく", "etymology": "lose face（顔を失う）という中国文化圏由来の表現。", "examples": {"B": "何を言っているかわからないように聞こえたら、クライアントの前で面子を失う。", "C": "発言を取り下げたくない。面子を失うかもしれないから。", "D": "恥ずかしい思いをする"}},
346: {"nativeDefinition": "To misunderstand each other due to miscommunication.", "japaneseMeaning": "（連絡が）すれ違う、誤解する", "etymology": "wires crossed（線が交差する）で、連絡がすれ違うことを表す。", "examples": {"B": "ごめん、連絡がすれ違っていた。君宛てのメッセージじゃなかった。別の人に送るべきだった。", "C": "え、君もこのタスクやってるの？連絡がすれ違ったみたいだ。僕も同じことをやっている。", "D": "誤解する"}},
347: {"nativeDefinition": "To improve one's level of performance.", "japaneseMeaning": "（実力を）上げる、腕を上げる", "etymology": "up one's game（ゲームを上げる）で、パフォーマンスを向上させることを表す。", "examples": {"B": "ゴールを決めるにはレベルアップしないと。相手は去年のチャンピオンだ。", "C": "レベッカは今夜までにレポートを終わらせたいなら、もっとレベルアップする必要がある。少し気が散っているみたいだ。", "D": "パフォーマンスのレベルを上げる"}},
348: {"nativeDefinition": "A broad term that covers many different things.", "japaneseMeaning": "総称、包括的な呼び方", "etymology": "catch-all（すべてを捕まえる）で、広く様々なものを含む用語を表す。", "examples": {"B": "日本では「酒」はあらゆるアルコール飲料の総称だが、他の国では通常日本酒を指す。", "C": "タピオカティーは台湾の茶ベースの飲み物の総称だが、最近はタピオカミルクティーを指すことが多い。", "D": "グループ化"}},
349: {"nativeDefinition": "To make significant changes to something.", "japaneseMeaning": "（何かを）大きく変える、刷新する", "etymology": "shake up（振って混ぜる）で、現状を大きく変えることを表す。", "examples": {"B": "朝にジムに行くように日常を変えた。良いかどうかはわからないけど、ルーティンを変えたかった。", "C": "ちょっと変化をつけたくて、1年ロシアに移住して英語を教えるつもりだ。", "D": "何かを大きく変える"}},
350: {"nativeDefinition": "Hopefully; said to avoid bad luck after expressing optimism.", "japaneseMeaning": "悪いことが起きませんように", "etymology": "木をノックする（knock on wood）西洋の迷信で、悪運を避けるジェスチャー。", "examples": {"B": "今日はツイてなかったけど、明日は良い日になる、悪いことが起きませんように。", "C": "悪いことが起きませんように、今度こそインターネット接続はうまくいくはずだ。", "D": "うまくいくといいな"}},
351: {"nativeDefinition": "If you are determined enough, you will find a way.", "japaneseMeaning": "意志があれば道は開ける", "etymology": "where there's a will（意志があれば）there's a way（方法がある）という教訓的な表現。", "examples": {"B": "彼は試験に合格できると強く信じている。過去12ヶ月全力を出してきた。意志があれば道は開ける。", "C": "次のフライトに間に合わないと思う？意志があれば道は開けるよ。", "D": "十分な努力があれば目標は達成される"}},
352: {"nativeDefinition": "To sound extremely unpleasant or irritating to someone.", "japaneseMeaning": "（音が）耳に痛い、聞いていられない", "etymology": "make one's ears bleed（耳から血が出る）という誇張表現で、耐えられない音を表す。", "examples": {"B": "コーヒーを飲むときにズルズル音を立てないで。耳に痛い。", "C": "最近の子どもが聴く音楽は本当に耳に痛い。", "D": "誰かにとって不快な音"}},
353: {"nativeDefinition": "To deceive someone by hiding the truth.", "japaneseMeaning": "（人を）欺く、目くらましをする", "etymology": "pull the wool over someone's eyes（目に羊毛を被せる）で、欺くことを表す。", "examples": {"B": "政府がまだ目くらましをしようとしているなんて信じられない。ニュースで全部報道されているのに。", "C": "ジョージは目くらましをしようとしたけど、昨日何が起きたかはもう知っていた。", "D": "人を欺く"}},
354: {"nativeDefinition": "To organize one's affairs or put things in order.", "japaneseMeaning": "身の回りを整える、内部をきちんとする", "etymology": "put one's house in order（家を整える）で、自分の問題を整理することを表す。", "examples": {"B": "ベネズエラは他国を攻撃するより、まず身の回りを整えるべきだ。自国の問題で十分だ。", "C": "身の回りを整えれば、顧客は戻ってくる。そうなればまた大儲けできる。", "D": "自分の事情を整理する"}},
355: {"nativeDefinition": "To treat something as unimportant or not serious.", "japaneseMeaning": "（何かを）軽く見る、油断する", "etymology": "take lightly（軽く取る）で、真剣に受け止めないことを表す。", "examples": {"B": "そのテストを軽く見てはいけない。以前多くの人がその科目で落ちている。", "C": "お母さん、成績が下がっているのはわかってるけど、授業を軽く見ているわけじゃない。今年はずっと難しいんだ。", "D": "何かを重要でないと扱う"}},
356: {"nativeDefinition": "To abandon someone to face danger or criticism alone.", "japaneseMeaning": "（人を）見捨てる、狼に渡す", "etymology": "throw someone to the wolves（人を狼に投げる）で、見捨てて危険にさらすことを表す。", "examples": {"B": "トムがデパートで高価な花瓶を落として、スタッフが来たとき僕を見捨てて自分が壊したと言った。", "C": "厳しい質問をされたとき、上司がサポートしてくれると思っていたのに、見捨てられた。", "D": "人を見捨てる"}},
357: {"nativeDefinition": "Something that provokes serious thought.", "japaneseMeaning": "考えさせられること、示唆に富む話", "etymology": "food for thought（思考の糧）で、深く考えさせる材料を表す。", "examples": {"B": "キャリアコーチが精神的に強い人がする18のことを挙げていた。本当に考えさせられる内容だった。", "C": "マイケルと人生の意味について深く話した。考えさせられる内容だった。", "D": "真剣に考える価値のあること"}},
358: {"nativeDefinition": "Visual representation conveys more than words.", "japaneseMeaning": "百聞は一見に如かず", "etymology": "a picture is worth a thousand words（絵は千の言葉に値する）という格言。", "examples": {"B": "この会社の仕組みを理解してもらうためにフローチャートを描くよ。百聞は一見に如かずだろ？", "C": "ピサの斜塔を知らないの？まさか。見たことないの？ちょっと待って、写真を見せるよ。百聞は一見に如かず。", "D": "言葉で説明するより見せた方がわかりやすい"}},
359: {"nativeDefinition": "Already dealt with or resolved.", "japaneseMeaning": "（もう）処理済みだ、済ませてある", "etymology": "taken care of（世話がされた）で、対応済みであることを表す。", "examples": {"B": "請求書はもう処理済みだから、支払いは心配しないで。", "C": "配送会社との問題はついに処理された。何が問題だったかようやくわかった。", "D": "解決済み"}},
360: {"nativeDefinition": "To leave quietly without being noticed.", "japaneseMeaning": "こっそり抜け出す", "etymology": "sneak out（こっそり出る）で、気づかれずに退出することを表す。", "examples": {"B": "午後、会議からこっそり抜け出す必要がある。", "C": "やばい、飲み物をこぼしちゃった。誰かに気づかれる前に映画館からこっそり抜けよう。", "D": "静かに出る"}},
361: {"nativeDefinition": "To reach a critical point where change becomes inevitable.", "japaneseMeaning": "転換点に達する、限界点に来る", "etymology": "tipping point（傾く点）で、変化が不可逆的になる臨界点を表す。", "examples": {"B": "地球温暖化は転換点に達した。今行動しなければ、被害は取り返しがつかなくなるかもしれない。", "C": "今年、世界人口の50%以上が初めて中産階級以上に分類され、経済の転換点に達した。", "D": "重要な転換点に到達する"}},
362: {"nativeDefinition": "To verify something by experiencing or observing it yourself.", "japaneseMeaning": "自分の目で確かめて", "etymology": "see for yourself（自分で見る）で、自分で確認することを表す。", "examples": {"B": "ねえ、部屋の隅に巨大なネズミがいるんだ。本当だよ。自分の目で確かめて。", "C": "東京は最近ずっと外国人に優しくなったと思うけど、来て自分の目で確かめてみて。", "D": "自分で確認する"}},
363: {"nativeDefinition": "To boast about one's own achievements.", "japaneseMeaning": "自慢する、自分を持ち上げる", "etymology": "blow one's own horn（自分のラッパを吹く）で、自慢することを表す。", "examples": {"B": "ナオミが昨日、スタバで番号を聞き出そうと自慢話ばかりする男の話をしてくれた。笑っちゃった。", "C": "自慢したくはないけど、歌は本当に上手いんだ。", "D": "自分を自慢する"}},
364: {"nativeDefinition": "No longer in danger or serious difficulty.", "japaneseMeaning": "危機を脱した、もう大丈夫だ", "etymology": "out of the woods（森を出る）で、危険な状況を脱したことを表す。", "examples": {"B": "赤ちゃんは約5ヶ月酸素が必要だったけど、もう危機を脱して元気だ。", "C": "日本経済はもう不況ではないが、まだ完全に危機を脱したわけではない。", "D": "困難から抜け出る"}},
365: {"nativeDefinition": "A mixture of good and bad periods in life.", "japaneseMeaning": "浮き沈み、良い時も悪い時もある", "etymology": "ups（上り）and downs（下り）で、人生の浮き沈みを表す。", "examples": {"B": "人生には浮き沈みがあると言うけど、僕は浮きを経験したことがない。どこにあるんだ？", "C": "去年は自動車メーカーにとって浮き沈みの年だったが、今年は挽回できると自信を持っている。", "D": "良い時と悪い時"}},
366: {"nativeDefinition": "Likely to become successful or prominent.", "japaneseMeaning": "将来有望な、注目の", "etymology": "up-and-coming（上がってくる）で、これから伸びることを表す。", "examples": {"B": "ニューヨークにはいつも最高の将来有望なファッションデザイナーがいる。だからニューヨークのファッションイベントが好きなんだ。", "C": "この人をチェックしてみて。コンテンツが素晴らしい将来有望なテック系ユーチューバーだ。", "D": "有望な"}},
367: {"nativeDefinition": "I will deal with a problem when it actually arises.", "japaneseMeaning": "その時になってから考える、臨機応変に対処する", "etymology": "cross that bridge when I get there（その橋に着いたとき渡る）で、先の問題は後で対処するという意味。", "examples": {"B": "学費を払うお金がないのにスタンフォードに応募した。まだ合格通知すら来ていない。臨機応変に対処するタイプだ。", "C": "僕は臨機応変に対処するタイプだから、全部に備えろと言われても見当違いだ。", "D": "必要になったときに対処する"}},
368: {"nativeDefinition": "Only just; by a very narrow margin.", "japaneseMeaning": "かろうじて、ぎりぎりで", "etymology": "by the skin of one's teeth（歯の皮一枚）で、かろうじてという意味の聖書由来の表現。", "examples": {"B": "かろうじて大学を卒業した。最後の学期の科目の期末試験はギリギリで合格した。", "C": "かろうじて会議に間に合った。あの会議を欠席していたら、今頃大変なことになっていた。", "D": "かろうじて"}},
369: {"nativeDefinition": "A strange or eccentric person.", "japaneseMeaning": "変人、風変わりな人", "etymology": "odd（変わった）＋ ball（人）で、普通と違う変わった人を表す。", "examples": {"B": "ジェイクは本当に変人だ。昼食に何を食べたか聞いたら、ニュートンの運動の法則の話を始めた。", "C": "みんな「テイラーはちょっと変人だから近づかない方がいい」みたいに言うけど、僕は彼女が違っていて好きなんだ。", "D": "変わった人"}},
370: {"nativeDefinition": "To take a risk, especially by speaking up or acting boldly.", "japaneseMeaning": "（危険を取って）身を挺する", "etymology": "stick one's neck out（首を突き出す）で、危険を冒して行動することを表す。", "examples": {"B": "同じ状況で相手がしてくれないなら、他人のために身を挺する必要はない。", "C": "株式取引で身を挺するたびに首を斬られる。いつ引き金を引くべきかわからない。", "D": "リスクを取る"}},
371: {"nativeDefinition": "To hurry to complete something at the last minute.", "japaneseMeaning": "（急いで）なんとか仕上げる", "etymology": "scramble（急いで動く）to get done（終わらせる）で、慌てて完成させることを表す。", "examples": {"B": "今慌てて仕上げているのは、いつまでに終わらせるべきか誰も教えてくれなかったからだ。", "C": "職場のパーソナルアシスタントは6時間おしゃべりして、最後の2時間で慌てて仕上げていた。", "D": "急いで何かを完了させる"}},
372: {"nativeDefinition": "A period of initial popularity or goodwill after starting something new.", "japaneseMeaning": "好意的な初期の時期、乗り気な時期", "etymology": "honeymoon（新婚旅行）期間が比喩的に、初期の好意的な期間を表す。", "examples": {"B": "カルロスは会社を立て直した後ヒーローと見なされたが、そのハネムーン期間は終わった。今は彼を追い出そうとしている。", "C": "政府はハネムーン期間中に不人気な法案を通そうとしている。", "D": "人気の初期期間"}},
373: {"nativeDefinition": "To make someone behave properly or stay disciplined.", "japaneseMeaning": "（人を）しっかりさせる、行儀よくさせる", "etymology": "keep in line（列に並ばせる）で、規律を守らせることを表す。", "examples": {"B": "あの先生は生徒をしっかりさせるのが本当に上手い。", "C": "自分をしっかりさせないと、このパーティーから追い出すよ。", "D": "人を行儀よくさせる"}},
374: {"nativeDefinition": "Nobody knows; it is impossible to say.", "japaneseMeaning": "神のみぞ知る、誰にもわからない", "etymology": "God only knows（神だけが知っている）で、誰にもわからないことを強調する表現。", "examples": {"B": "死後の世界があるかどうかは神のみぞ知る。だから人生を楽しむ方がいいと思う。", "C": "試験に合格できると自信はあるけど、何が起きるかは神のみぞ知るよね？", "D": "わからない"}},
375: {"nativeDefinition": "Something that helps recall or review previously learned information.", "japaneseMeaning": "おさらい、思い出しの助け", "etymology": "refresh（リフレッシュする）が名詞化し、記憶をよみがえらせるものを表す。", "examples": {"B": "このゲーム懐かしい！遊び方をおさらいする必要がある。6歳のとき以来プレイしていない。", "C": "前回のエピソードで何が起きたか素早くおさらいしたいなら、この要約を読むといい。", "D": "簡潔な思い出し"}},
376: {"nativeDefinition": "To make a gesture of peace or reconciliation.", "japaneseMeaning": "和平の申し出をする、仲直りのきっかけを作る", "etymology": "extend an olive branch（オリーブの枝を差し出す）が聖書から、和解の申し出を表す。", "examples": {"B": "自分に非がなくても、和平の申し出をする側にならないと、長続きする関係は築けない。", "C": "彼女と喧嘩したとき、いつも僕の方から仲直りのきっかけを作らないといけない。", "D": "争いの解決を始める"}},
377: {"nativeDefinition": "To assume success before it is certain.", "japaneseMeaning": "勝ったつもりになる、早とちりする", "etymology": "卵が孵る前にひな鳥を数える（count chickens before they hatch）という比喩。", "examples": {"B": "3点リードしているけど、勝ったつもりになるな。これまでにもこの状況から負けた強いチームがある。", "C": "入学式のドレスを選びたいのはわかるけど、早とちりはするな。まだ試験結果が出ていない。", "D": "最終結果の前に成功を確信しすぎる"}},
378: {"nativeDefinition": "To arrive gradually in small numbers.", "japaneseMeaning": "（人が）ぽつぽつと到着する", "etymology": "trickle（したたる）in（入る）で、少しずつ到着することを表す。", "examples": {"B": "チームには9時に来るよう言ったのに、9時半からぽつぽつと到着した。再発防止のルールを決める必要がある。", "C": "誰も来ないんじゃないかと心配していたけど、人がぽつぽつと到着し始めた。ほっとした。", "D": "少人数ずつ徐々に到着する"}},
379: {"nativeDefinition": "To increase the importance or intensity of a situation.", "japaneseMeaning": "（状況の）賭け金を上げる、重大度を高める", "etymology": "raise the stakes（賭け金を上げる）が比喩的に、状況の重大さを高めることを表す。", "examples": {"B": "賞金が倍になったことで、競争の賭け金が大幅に上がった。", "C": "上司は僕の話を聞こうとしたことがないから、辞任をちらつかせて賭け金を上げることにした。", "D": "話題の重要性を高める"}},
380: {"nativeDefinition": "Without conditions or obligations attached.", "japaneseMeaning": "条件なしで、何の縛りもなく", "etymology": "no strings attached（紐がついていない）で、条件や義務がないことを表す。", "examples": {"B": "この車、条件なしで半額で売るよ。どう？", "C": "毎週火曜日、角のドーナツ屋は全品20%オフで、条件なしだって知ってた？", "D": "条件が付いていない"}},
381: {"nativeDefinition": "To refuse to acknowledge or face an unpleasant reality.", "japaneseMeaning": "現実から目を背ける、問題を無視する", "etymology": "bury one's head in the sand（頭を砂に埋める）というダチョウの俗説に由来する比喩。", "examples": {"B": "いくら現実から目を背けても、妻が怒っている問題は消えないよ。", "C": "この問題から目を背けられない。電車の過密は深刻な社会問題だ。", "D": "不快な事実を意図的に無視する"}},
382: {"nativeDefinition": "To increase one's commitment or effort toward something.", "japaneseMeaning": "（努力を）倍増する、一層注力する", "etymology": "double down（倍に賭ける）がカジノ用語から、さらに力を入れることを表す。", "examples": {"B": "今年の目標は、健康と知識への個人的な投資を一層注力することだ。", "C": "ネットフリックスが今年アニメに一層注力するというのは聞いてうれしい話だ。かなり大きなことだと思う。", "D": "もっと努力を注ぐ"}},
383: {"nativeDefinition": "To become the main focus of attention.", "japaneseMeaning": "主役になる、注目の的になる", "etymology": "take center stage（中央の舞台に立つ）で、注目の中心になることを表す。", "examples": {"B": "適切にマーケティングされれば、この新製品は主役になる。広告は全力で進めよう。", "C": "彼女は注目を集めたがるタイプだ。何をするにも主役になろうとする。", "D": "多くの注目を集める"}},
384: {"nativeDefinition": "Extremely luxurious and of the highest quality.", "japaneseMeaning": "王様も満足するほど豪華な", "etymology": "fit for a king（王にふさわしい）で、最高級の豪華さを表す。", "examples": {"B": "ホテルの部屋は王様も満足するほど豪華だった。ちょっとやりすぎかもしれないけど、大好きだ。", "C": "昨夜シェフが出した宴会料理は王様も満足するほど豪華だった。スープだけで2時間かけたらしい。", "D": "豪華な"}},
385: {"nativeDefinition": "A critical weakness despite overall strength.", "japaneseMeaning": "致命的な弱点、唯一の弱点", "etymology": "ギリシャ神話のアキレスの踵（heel）から、唯一の弱点を表す。", "examples": {"B": "彼の致命的な弱点はPKだ。PKのときに冷静さを保てないようだ。", "C": "ハチミツはプーさんの致命的な弱点だ。かわいい。", "D": "大きな弱点"}},
386: {"nativeDefinition": "To exaggerate the importance or severity of something.", "japaneseMeaning": "（何かを）大げさに言う、誇張する", "etymology": "play up（大きくする）で、重要性を誇張することを表す。", "examples": {"B": "子どものインターネット利用の危険性はメディアが大げさに言っていると思う。学べることもたくさんあるはずだ。", "C": "マークは週末に見た映画が史上最高だと言ったけど、少し大げさだと思う。良かったけど最高ではなかった。", "D": "何かを誇張する"}},
387: {"nativeDefinition": "To break down and analyze something from different angles.", "japaneseMeaning": "（情報などを）細かく分けて分析する", "etymology": "slice and dice（切って刻む）が比喩的に、多角的に分析することを表す。", "examples": {"B": "この世界は主観的な解釈の積み重ねだ。物事の切り方で世界の見え方が本当に変わる。", "C": "この複雑な戦略を組み立てようとしているけど、まだうまくいかない。いろんな切り口で分けられる。", "D": "分析のために再配置する"}},
388: {"nativeDefinition": "Not fully thought through; poorly developed.", "japaneseMeaning": "半端な、熟考されていない", "etymology": "half-baked（半焼きの）で、十分に練られていないことを表す。", "examples": {"B": "これはまだ半端なアイデアだけど、人気のハウスミュージックのデータベースを作って音のパターンを分析し、曲を作るのは面白いと思う。", "C": "コリンズの事故の言い訳はかなり半端だ。東京の道路の真ん中に突然カンガルーが現れたなんて誰が信じる？", "D": "粗い"}},
389: {"nativeDefinition": "A widely circulated story of doubtful truth.", "japaneseMeaning": "都市伝説", "etymology": "urban（都市の）legend（伝説）で、都市で広まる真偽不明の話を表す。", "examples": {"B": "ニューヨークの下水道にワニがいるのは都市伝説じゃない。考えてみれば、観光客を増やすために作られた話かもしれない。", "C": "人面犬は聞いた中で最も怖い日本の都市伝説の一つだ。ただし実際に目撃されたことはない。", "D": "根拠のない話"}},
390: {"nativeDefinition": "To compel someone to act because circumstances leave no choice.", "japaneseMeaning": "（人に）余儀なくさせる、追い込む", "etymology": "force someone's hand（手を強いる）で、選択肢なく行動させることを表す。", "examples": {"B": "このワインは後で飲むつもりだったけど、トムに開けさせられた。今日は彼の誕生日だから、何をされてもいい。", "C": "息が臭かったからミントを渡した。親切にしようとしたけど、断られたから仕方なく理由を言った。", "D": "人に行動を余儀なくさせる"}},
391: {"nativeDefinition": "If there are signs of a problem, there usually is one.", "japaneseMeaning": "噂には根拠がある、煙のあるところに火あり", "etymology": "where there's smoke there's fire（煙があるところに火がある）という格言。", "examples": {"B": "リサがテストでカンニングしたと生徒たちが言っている。噂には根拠がある。", "C": "容疑者は何も悪いことはしていないと言う。でも経験上、噂には根拠がある。", "D": "何か悪い兆候があれば、たいてい何か問題がある"}},
392: {"nativeDefinition": "To sense that something is suspicious or dishonest.", "japaneseMeaning": "怪しいと感じる、においを嗅ぎ取る", "etymology": "smell a rat（ネズミの臭いを嗅ぐ）で、不正を嗅ぎ取ることを表す。", "examples": {"B": "18歳の女の子が68歳の男と付き合っている。彼はすごいけど、何か怪しい。", "C": "プロフィールはアメリカ人と書いてあるのに、前髪をfringesと言う。怪しい。当てずっぽうだけど、イギリス人だと思う。", "D": "怪しいと感じる"}},
393: {"nativeDefinition": "Even enjoyable experiences must eventually end.", "japaneseMeaning": "良いことにも終わりはある", "etymology": "all good things must come to an end（すべての良いことには終わりがある）という教訓。", "examples": {"B": "このパーティーをあと5時間続けたい。でも良いことにも終わりはある。", "C": "良いことにも終わりはあるのはわかっているけど、スタバにあと30分いてもいい？話を中断したくない。", "D": "楽しい経験でも永遠には続かない"}},
394: {"nativeDefinition": "Ultimately; when everything is considered.", "japaneseMeaning": "結局のところ、最終的には", "etymology": "when all's said and done（すべてが言われ終わったとき）で、最終的な結論を述べる表現。", "examples": {"B": "結局のところ、週末に何時間働いたかなんて誰も気にしない。生み出したものがすべてだ。", "C": "結局のところ、どうやって勝つかは関係ない。何が何でも勝たなきゃいけない。", "D": "最終的には"}},
395: {"nativeDefinition": "To pursue long-term goals rather than immediate gains.", "japaneseMeaning": "長期戦で行く、将来を見据えて動く", "etymology": "play the long game（長いゲームをする）で、短期的利益より長期戦略を取ることを表す。", "examples": {"B": "ティムはヨーロッパで遊んでいるだけだと思っていたけど、ずっと長期戦で動いていた。新しいビジネスの市場調査をしていたんだ。", "C": "無給のインターンで長期戦を選んでいる。今は稼いでいないけど、将来良い仕事につながるはずだ。", "D": "長期計画に基づいて行動する"}},
396: {"nativeDefinition": "Small details are often the hardest part to get right.", "japaneseMeaning": "細部に神が宿る、細かいところが難しい", "etymology": "devil's in the detail（細部に悪魔がいる）で、見落としがちな細部の難しさを表す。", "examples": {"B": "モーツァルトの曲は演奏しやすそうに見えるけど、細部に神が宿る。", "C": "プロがサーフィンするのは簡単そうに見える。でも細部に神が宿る。すべてが寸分たがわずでなければならない。", "D": "細かい部分を正しくするのが難しい"}},
397: {"nativeDefinition": "To have a decisive advantage in a situation.", "japaneseMeaning": "すべての切り札を握っている", "etymology": "hold all the cards（すべてのカードを握る）で、交渉などで優位に立つことを表す。", "examples": {"B": "キムは給与交渉ですべての切り札を握っている。彼女が必要だとわかっているから。", "C": "今はこちらがすべての切り札を握っている。もっと良い条件を求めるべきだ。交渉を本格化しよう。", "D": "大きな優位性を持つ"}},
398: {"nativeDefinition": "Used when two people have the same good idea independently.", "japaneseMeaning": "考えが同じだね、お互い様だね", "etymology": "great minds think alike（偉大な心は同じように考える）という、同じ考えに至ったときの冗談めいた表現。", "examples": {"B": "兄と僕、今日同じシャツを着ている。考えが同じだね。", "C": "サラと僕、お互いに同じクリスマスプレゼントを贈り合った。お互い様だね。", "D": "同じ良いアイデアを持っていた"}},
399: {"nativeDefinition": "A comfortable, enjoyable, and affluent way of living.", "japaneseMeaning": "豊かで快適な生活", "etymology": "the good life（良い人生）で、裕福で満足できる生活を表す。", "examples": {"B": "彼のインスタの休暇写真を見ると本当に幸せな気持ちになる。あれこそ豊かな生活だ。", "C": "ジェレミーは生まれながらの金持ちだ。両親が全ての学費を払ってくれた。それが豊かな生活だ。", "D": "質の高い暮らし方"}},
400: {"nativeDefinition": "To have strict control over someone.", "japaneseMeaning": "（人を）がっちり繋いでいる、厳しく管理している", "etymology": "on a leash（リードにつながれて）で、犬のように厳しく管理されていることを表す。", "examples": {"B": "ポールは彼女にがっちり繋がれている。金曜の飲み会にももう出てこない。", "C": "仕事がエミリーをがっちり繋いでいる。何週間も会っていない。上司が本当に厳しい。", "D": "人を厳しく管理している"}},
}
